import{_ as i,o as t,c as r,a2 as a}from"./chunks/framework.Bk_3gXAz.js";const m=JSON.parse('{"title":"vercel-react-best-practices","description":"React and Next.js performance optimization guidelines from Vercel Engineering. This skill should be used when writing, reviewing, or refactoring React/Next.js code to ensure optimal performance patterns. Triggers on tasks involving React components, Next.js pages, data fetching, bundle optimization, or performance improvements.","frontmatter":{"title":"vercel-react-best-practices","name":"vercel-react-best-practices","description":"React and Next.js performance optimization guidelines from Vercel Engineering. This skill should be used when writing, reviewing, or refactoring React/Next.js code to ensure optimal performance patterns. Triggers on tasks involving React components, Next.js pages, data fetching, bundle optimization, or performance improvements.","license":"MIT","metadata":{"author":"vercel","version":"1.0.0"}},"headers":[],"relativePath":"skills/vercel-react-best-practices.md","filePath":"skills/vercel-react-best-practices.md"}'),o={name:"skills/vercel-react-best-practices.md"};function n(d,e,l,c,s,p){return t(),r("div",null,[...e[0]||(e[0]=[a(`<h1 id="vercel-react-best-practices" tabindex="-1">Vercel React Best Practices <a class="header-anchor" href="#vercel-react-best-practices" aria-label="Permalink to &quot;Vercel React Best Practices&quot;">​</a></h1><p>Comprehensive performance optimization guide for React and Next.js applications, maintained by Vercel. Contains 64 rules across 8 categories, prioritized by impact to guide automated refactoring and code generation.</p><h2 id="when-to-apply" tabindex="-1">When to Apply <a class="header-anchor" href="#when-to-apply" aria-label="Permalink to &quot;When to Apply&quot;">​</a></h2><p>Reference these guidelines when:</p><ul><li>Writing new React components or Next.js pages</li><li>Implementing data fetching (client or server-side)</li><li>Reviewing code for performance issues</li><li>Refactoring existing React/Next.js code</li><li>Optimizing bundle size or load times</li></ul><h2 id="rule-categories-by-priority" tabindex="-1">Rule Categories by Priority <a class="header-anchor" href="#rule-categories-by-priority" aria-label="Permalink to &quot;Rule Categories by Priority&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Priority</th><th>Category</th><th>Impact</th><th>Prefix</th></tr></thead><tbody><tr><td>1</td><td>Eliminating Waterfalls</td><td>CRITICAL</td><td><code>async-</code></td></tr><tr><td>2</td><td>Bundle Size Optimization</td><td>CRITICAL</td><td><code>bundle-</code></td></tr><tr><td>3</td><td>Server-Side Performance</td><td>HIGH</td><td><code>server-</code></td></tr><tr><td>4</td><td>Client-Side Data Fetching</td><td>MEDIUM-HIGH</td><td><code>client-</code></td></tr><tr><td>5</td><td>Re-render Optimization</td><td>MEDIUM</td><td><code>rerender-</code></td></tr><tr><td>6</td><td>Rendering Performance</td><td>MEDIUM</td><td><code>rendering-</code></td></tr><tr><td>7</td><td>JavaScript Performance</td><td>LOW-MEDIUM</td><td><code>js-</code></td></tr><tr><td>8</td><td>Advanced Patterns</td><td>LOW</td><td><code>advanced-</code></td></tr></tbody></table><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><h3 id="_1-eliminating-waterfalls-critical" tabindex="-1">1. Eliminating Waterfalls (CRITICAL) <a class="header-anchor" href="#_1-eliminating-waterfalls-critical" aria-label="Permalink to &quot;1. Eliminating Waterfalls (CRITICAL)&quot;">​</a></h3><ul><li><code>async-defer-await</code> - Move await into branches where actually used</li><li><code>async-parallel</code> - Use Promise.all() for independent operations</li><li><code>async-dependencies</code> - Use better-all for partial dependencies</li><li><code>async-api-routes</code> - Start promises early, await late in API routes</li><li><code>async-suspense-boundaries</code> - Use Suspense to stream content</li></ul><h3 id="_2-bundle-size-optimization-critical" tabindex="-1">2. Bundle Size Optimization (CRITICAL) <a class="header-anchor" href="#_2-bundle-size-optimization-critical" aria-label="Permalink to &quot;2. Bundle Size Optimization (CRITICAL)&quot;">​</a></h3><ul><li><code>bundle-barrel-imports</code> - Import directly, avoid barrel files</li><li><code>bundle-dynamic-imports</code> - Use next/dynamic for heavy components</li><li><code>bundle-defer-third-party</code> - Load analytics/logging after hydration</li><li><code>bundle-conditional</code> - Load modules only when feature is activated</li><li><code>bundle-preload</code> - Preload on hover/focus for perceived speed</li></ul><h3 id="_3-server-side-performance-high" tabindex="-1">3. Server-Side Performance (HIGH) <a class="header-anchor" href="#_3-server-side-performance-high" aria-label="Permalink to &quot;3. Server-Side Performance (HIGH)&quot;">​</a></h3><ul><li><code>server-auth-actions</code> - Authenticate server actions like API routes</li><li><code>server-cache-react</code> - Use React.cache() for per-request deduplication</li><li><code>server-cache-lru</code> - Use LRU cache for cross-request caching</li><li><code>server-dedup-props</code> - Avoid duplicate serialization in RSC props</li><li><code>server-hoist-static-io</code> - Hoist static I/O (fonts, logos) to module level</li><li><code>server-serialization</code> - Minimize data passed to client components</li><li><code>server-parallel-fetching</code> - Restructure components to parallelize fetches</li><li><code>server-after-nonblocking</code> - Use after() for non-blocking operations</li></ul><h3 id="_4-client-side-data-fetching-medium-high" tabindex="-1">4. Client-Side Data Fetching (MEDIUM-HIGH) <a class="header-anchor" href="#_4-client-side-data-fetching-medium-high" aria-label="Permalink to &quot;4. Client-Side Data Fetching (MEDIUM-HIGH)&quot;">​</a></h3><ul><li><code>client-swr-dedup</code> - Use SWR for automatic request deduplication</li><li><code>client-event-listeners</code> - Deduplicate global event listeners</li><li><code>client-passive-event-listeners</code> - Use passive listeners for scroll</li><li><code>client-localstorage-schema</code> - Version and minimize localStorage data</li></ul><h3 id="_5-re-render-optimization-medium" tabindex="-1">5. Re-render Optimization (MEDIUM) <a class="header-anchor" href="#_5-re-render-optimization-medium" aria-label="Permalink to &quot;5. Re-render Optimization (MEDIUM)&quot;">​</a></h3><ul><li><code>rerender-defer-reads</code> - Don&#39;t subscribe to state only used in callbacks</li><li><code>rerender-memo</code> - Extract expensive work into memoized components</li><li><code>rerender-memo-with-default-value</code> - Hoist default non-primitive props</li><li><code>rerender-dependencies</code> - Use primitive dependencies in effects</li><li><code>rerender-derived-state</code> - Subscribe to derived booleans, not raw values</li><li><code>rerender-derived-state-no-effect</code> - Derive state during render, not effects</li><li><code>rerender-functional-setstate</code> - Use functional setState for stable callbacks</li><li><code>rerender-lazy-state-init</code> - Pass function to useState for expensive values</li><li><code>rerender-simple-expression-in-memo</code> - Avoid memo for simple primitives</li><li><code>rerender-split-combined-hooks</code> - Split hooks with independent dependencies</li><li><code>rerender-move-effect-to-event</code> - Put interaction logic in event handlers</li><li><code>rerender-transitions</code> - Use startTransition for non-urgent updates</li><li><code>rerender-use-deferred-value</code> - Defer expensive renders to keep input responsive</li><li><code>rerender-use-ref-transient-values</code> - Use refs for transient frequent values</li><li><code>rerender-no-inline-components</code> - Don&#39;t define components inside components</li></ul><h3 id="_6-rendering-performance-medium" tabindex="-1">6. Rendering Performance (MEDIUM) <a class="header-anchor" href="#_6-rendering-performance-medium" aria-label="Permalink to &quot;6. Rendering Performance (MEDIUM)&quot;">​</a></h3><ul><li><code>rendering-animate-svg-wrapper</code> - Animate div wrapper, not SVG element</li><li><code>rendering-content-visibility</code> - Use content-visibility for long lists</li><li><code>rendering-hoist-jsx</code> - Extract static JSX outside components</li><li><code>rendering-svg-precision</code> - Reduce SVG coordinate precision</li><li><code>rendering-hydration-no-flicker</code> - Use inline script for client-only data</li><li><code>rendering-hydration-suppress-warning</code> - Suppress expected mismatches</li><li><code>rendering-activity</code> - Use Activity component for show/hide</li><li><code>rendering-conditional-render</code> - Use ternary, not &amp;&amp; for conditionals</li><li><code>rendering-usetransition-loading</code> - Prefer useTransition for loading state</li><li><code>rendering-resource-hints</code> - Use React DOM resource hints for preloading</li><li><code>rendering-script-defer-async</code> - Use defer or async on script tags</li></ul><h3 id="_7-javascript-performance-low-medium" tabindex="-1">7. JavaScript Performance (LOW-MEDIUM) <a class="header-anchor" href="#_7-javascript-performance-low-medium" aria-label="Permalink to &quot;7. JavaScript Performance (LOW-MEDIUM)&quot;">​</a></h3><ul><li><code>js-batch-dom-css</code> - Group CSS changes via classes or cssText</li><li><code>js-index-maps</code> - Build Map for repeated lookups</li><li><code>js-cache-property-access</code> - Cache object properties in loops</li><li><code>js-cache-function-results</code> - Cache function results in module-level Map</li><li><code>js-cache-storage</code> - Cache localStorage/sessionStorage reads</li><li><code>js-combine-iterations</code> - Combine multiple filter/map into one loop</li><li><code>js-length-check-first</code> - Check array length before expensive comparison</li><li><code>js-early-exit</code> - Return early from functions</li><li><code>js-hoist-regexp</code> - Hoist RegExp creation outside loops</li><li><code>js-min-max-loop</code> - Use loop for min/max instead of sort</li><li><code>js-set-map-lookups</code> - Use Set/Map for O(1) lookups</li><li><code>js-tosorted-immutable</code> - Use toSorted() for immutability</li><li><code>js-flatmap-filter</code> - Use flatMap to map and filter in one pass</li></ul><h3 id="_8-advanced-patterns-low" tabindex="-1">8. Advanced Patterns (LOW) <a class="header-anchor" href="#_8-advanced-patterns-low" aria-label="Permalink to &quot;8. Advanced Patterns (LOW)&quot;">​</a></h3><ul><li><code>advanced-event-handler-refs</code> - Store event handlers in refs</li><li><code>advanced-init-once</code> - Initialize app once per app load</li><li><code>advanced-use-latest</code> - useLatest for stable callback refs</li></ul><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><p>Read individual rule files for detailed explanations and code examples:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rules/async-parallel.md</span></span>
<span class="line"><span>rules/bundle-barrel-imports.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Each rule file contains:</p><ul><li>Brief explanation of why it matters</li><li>Incorrect code example with explanation</li><li>Correct code example with explanation</li><li>Additional context and references</li></ul><h2 id="full-compiled-document" tabindex="-1">Full Compiled Document <a class="header-anchor" href="#full-compiled-document" aria-label="Permalink to &quot;Full Compiled Document&quot;">​</a></h2><p>For the complete guide with all rules expanded: <code>AGENTS.md</code></p>`,31)])])}const h=i(o,[["render",n]]);export{m as __pageData,h as default};
